import{_ as e,o as a,c as t}from"./chunks/framework.KHntoz-C.js";const u=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Lingua","text":"Database-driven translations for Laravel","tagline":"Install languages, manage translations, and switch locales — all through a beautiful Livewire UI, with zero deployments.","image":{"src":"/public/logoLinguaVertical.svg","alt":"Lingua UI"},"actions":[{"theme":"brand","text":"Get Started","link":"/guide/introduction"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/rivalex/lingua"}]},"features":[{"icon":"🗄️","title":"Database-backed translations","details":"All translations live in the database and are editable instantly — no file deploys needed. Spatie's laravel-translation-loader handles the loading layer."},{"icon":"⚡","title":"Livewire + Flux UI","details":"Reactive, real-time management interface built with Livewire 4 and Flux 2. Every action — add language, edit translation, sync — happens without a page reload."},{"icon":"🔄","title":"Bi-directional sync","details":"Import your existing PHP/JSON lang files into the database with one command, or export everything back to files for version control and deployments."},{"icon":"🌐","title":"70+ languages","details":"Install any locale from the Laravel Lang ecosystem with a single Artisan command. Language files, DB records, and translations are set up automatically."},{"icon":"✍️","title":"Rich text support","details":"Each translation can be plain text, HTML, or Markdown. The correct editor activates automatically based on the translation type."},{"icon":"↔️","title":"RTL / LTR support","details":"Arabic, Hebrew, Persian and other RTL languages are fully supported. Lingua stores and exposes the text direction for every language."},{"icon":"📦","title":"Vendor translations","details":"Manage package translations (validation messages, pagination, etc.) alongside your own strings, with built-in protection against accidental deletion."},{"icon":"📊","title":"Progress tracking","details":"Every language shows a completion percentage and missing-translation count so you always know what needs translating."},{"icon":"🧪","title":"Fully tested","details":"150+ Pest tests covering all Artisan commands, Livewire components, Blade components, helpers, and the complete facade API."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}`),n={name:"index.md"};function i(o,l,s,r,d,c){return a(),t("div")}const p=e(n,[["render",i]]);export{u as __pageData,p as default};
